//帮别人调
#include<bits/stdc++.h>
using namespace std;
string s,w[105],str="";
int n,cnt,vis[105];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>w[i];
        for(int j=0;j<w[i].size();j++)
            w[i][j]=(w[i][j]>='A' && w[i][j]<='Z'? w[i][j]+32:w[i][j]);//大小写统一
    }
    getchar();
    getline(cin,s);
    transform(s.begin(),s.end(),s.begin(),::tolower);
    for(int i=0;i<s.size();i++){
		if(s[i]=='.'){
			for(int j=1;j<=n;j++){
				if(str==w[j]&&!vis[j]){
					vis[j]=1;
					cnt++;
					break;
				}
			}
			str="";
			memset(vis,0,sizeof(vis));
		}
		else if(s[i]==' ' || s[i]==','){//还有逗号
			for(int j=1;j<=n;j++){
				if(str==w[j]&&!vis[j]){
					vis[j]=1;
					cnt++;
					break;
				}
			}
			str="";
		}else{//不要把标点加进去了
		    s[i]=(s[i]>='A' && s[i]<='Z'? s[i]+32:s[i]);//还是大小写统一
		    str+=s[i];
		}
	}
	cout<<cnt;
    return 0;
}
